import{_ as a,c as t,o as i,aN as e}from"./chunks/framework.CqA5BTDU.js";const c=JSON.parse('{"title":"Harbor 镜像仓库","description":"","frontmatter":{},"headers":[],"relativePath":"09.容器化/10-Harbor镜像仓库.md","filePath":"09.容器化/10-Harbor镜像仓库.md","lastUpdated":null}'),n={name:"09.容器化/10-Harbor镜像仓库.md"};function p(r,s,d,h,l,o){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="harbor-镜像仓库" tabindex="-1">Harbor 镜像仓库 <a class="header-anchor" href="#harbor-镜像仓库" aria-label="Permalink to &quot;Harbor 镜像仓库&quot;">​</a></h1><p>镜像仓库负责保存、分发和管理镜像。Docker Hub 用来拉公共镜像，公司内部服务放到私有仓库（Harbor、云厂商镜像仓库或自建 registry）里。镜像仓库不是单纯的文件服务器——除了存镜像，还要处理认证、权限、标签、漏洞扫描、保留策略和审计记录。</p><h2 id="仓库在链路里的位置" tabindex="-1">仓库在链路里的位置 <a class="header-anchor" href="#仓库在链路里的位置" aria-label="Permalink to &quot;仓库在链路里的位置&quot;">​</a></h2><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20code%5B%22%E4%BB%A3%E7%A0%81%E4%BB%93%E5%BA%93%22%5D%20--%3E%20ci%5B%22CI%20%E6%9E%84%E5%BB%BA%22%5D%0A%20%20%20%20ci%20--%3E%20image%5B%22%E7%94%9F%E6%88%90%E9%95%9C%E5%83%8F%22%5D%0A%20%20%20%20image%20--%3E%20registry%5B%22%E9%95%9C%E5%83%8F%E4%BB%93%E5%BA%93%22%5D%0A%20%20%20%20registry%20--%3E%20host%5B%22%E8%BF%90%E8%A1%8C%E8%8A%82%E7%82%B9%22%5D%0A%20%20%20%20host%20--%3E%20container%5B%22%E5%AE%B9%E5%99%A8%22%5D%0A"></div><p>镜像加速源和镜像仓库不是一回事。<code>registry-mirrors</code> 解决的是从 Docker Hub 拉公共镜像慢的问题；Harbor、云厂商仓库解决的是内部镜像保存、权限、分发、审计和清理。</p><h2 id="仓库类型" tabindex="-1">仓库类型 <a class="header-anchor" href="#仓库类型" aria-label="Permalink to &quot;仓库类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>Docker Hub</td><td>公共镜像主要来源</td></tr><tr><td>Harbor</td><td>常见企业私有仓库，支持项目、权限、扫描、复制、垃圾回收</td></tr><tr><td>云厂商仓库</td><td>和云上 IAM、集群、镜像加速集成方便</td></tr><tr><td>registry</td><td>Docker 官方轻量仓库，功能简单，适合实验</td></tr></tbody></table><p>教学和小实验用 registry 够用，公司内部环境更偏向 Harbor——权限、项目隔离、清理策略和漏洞扫描这些能力后面都会用上。</p><h2 id="登录、推送和拉取" tabindex="-1">登录、推送和拉取 <a class="header-anchor" href="#登录、推送和拉取" aria-label="Permalink to &quot;登录、推送和拉取&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 输入用户名和密码或 token</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tag</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo-app:1.0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/ops/demo-app:1.0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/ops/demo-app:1.0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/ops/demo-app:1.0</span></span></code></pre></div><p>镜像名里的 <code>ops</code> 通常对应仓库里的项目或命名空间。权限控制一般也按项目划分——应用、基础镜像、测试镜像分开，不全部塞进一个项目。</p><h2 id="harbor-部署" tabindex="-1">Harbor 部署 <a class="header-anchor" href="#harbor-部署" aria-label="Permalink to &quot;Harbor 部署&quot;">​</a></h2><p>Harbor 常用 Docker Compose 部署。部署前准备好域名、证书、数据目录和配置文件。</p><p>目录规划：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/opt/harbor/</span></span>
<span class="line"><span>├── harbor.yml</span></span>
<span class="line"><span>├── common/</span></span>
<span class="line"><span>└── data/</span></span></code></pre></div><p><code>harbor.yml</code> 里几个关键字段：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">hostname</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">registry.example.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">https</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">443</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  certificate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/opt/harbor/certs/registry.example.com.crt</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  private_key</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/opt/harbor/certs/registry.example.com.key</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">harbor_admin_password</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">change_this_password</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">database</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  password</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">change_this_db_password</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">data_volume</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/opt/harbor/data</span></span></code></pre></div><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>hostname</code></td><td>客户端访问仓库的域名或地址</td></tr><tr><td><code>https</code></td><td>HTTPS 证书配置</td></tr><tr><td><code>harbor_admin_password</code></td><td>初始管理员密码</td></tr><tr><td><code>database.password</code></td><td>Harbor 内置数据库密码</td></tr><tr><td><code>data_volume</code></td><td>镜像和组件数据目录</td></tr></tbody></table><p>安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/harbor</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./prepare</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 根据 harbor.yml 生成组件配置</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span></span></code></pre></div><p>生产环境通常使用 HTTPS。内网临时环境如果使用 HTTP，要明确 Docker daemon 的 insecure registry 配置范围——默认信任范围放得太大，后续迁移和审计都会麻烦。</p><h2 id="客户端证书和-insecure-registry" tabindex="-1">客户端证书和 insecure registry <a class="header-anchor" href="#客户端证书和-insecure-registry" aria-label="Permalink to &quot;客户端证书和 insecure registry&quot;">​</a></h2><p>使用自签证书时，客户端要信任 Harbor 的 CA 证书：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/docker/certs.d/registry.example.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com.crt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/docker/certs.d/registry.example.com/ca.crt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker</span></span></code></pre></div><p>如果使用 HTTP 或自签证书又不配 CA，Docker 会报证书或协议错误。临时 insecure registry 配置写在 <code>/etc/docker/daemon.json</code>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;insecure-registries&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;registry.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>改完重启 Docker：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Insecure Registries&quot;</span></span></code></pre></div><p>insecure registry 只适合受控内网临时使用。仓库账号和镜像内容经过不受信任的链路时，HTTP 非常危险。</p><h2 id="项目和权限" tabindex="-1">项目和权限 <a class="header-anchor" href="#项目和权限" aria-label="Permalink to &quot;项目和权限&quot;">​</a></h2><p>Harbor 里的对象层级：</p><table tabindex="0"><thead><tr><th>对象</th><th>说明</th></tr></thead><tbody><tr><td>Project</td><td>项目空间，隔离镜像和权限</td></tr><tr><td>Repository</td><td>镜像仓库，如 <code>ops/demo-app</code></td></tr><tr><td>Artifact</td><td>某个镜像版本或 OCI artifact</td></tr><tr><td>Tag</td><td>镜像标签</td></tr><tr><td>Robot Account</td><td>给 CI/CD 使用的机器人账号</td></tr></tbody></table><p>CI/CD 推镜像适合用 Robot Account 而非个人管理员账号。机器人账号权限更容易收窄（只给某个项目的 push 权限），泄露后也方便单独吊销，不影响其他项目。</p><h2 id="保留和清理策略" tabindex="-1">保留和清理策略 <a class="header-anchor" href="#保留和清理策略" aria-label="Permalink to &quot;保留和清理策略&quot;">​</a></h2><p>镜像仓库很容易被旧版本撑满。常见保留策略：</p><table tabindex="0"><thead><tr><th>规则</th><th>示例</th></tr></thead><tbody><tr><td>保留最近 N 个</td><td>每个仓库保留最近 20 个 release 标签</td></tr><tr><td>按前缀过滤</td><td>保留 <code>prod-*</code>，清理 <code>dev-*</code></td></tr><tr><td>保留不可变版本</td><td>正式发布版本不覆盖、不删除</td></tr><tr><td>按时间清理</td><td>CI 临时标签自动过期</td></tr></tbody></table><p>Harbor 删除 tag 后还要执行垃圾回收（GC）才会真正释放存储空间。清理策略先在测试项目验证，多环境共用仓库时，误删镜像会直接导致回滚失败。</p><h2 id="镜像标签的不可变性" tabindex="-1">镜像标签的不可变性 <a class="header-anchor" href="#镜像标签的不可变性" aria-label="Permalink to &quot;镜像标签的不可变性&quot;">​</a></h2><p>正式发布镜像不适合反复覆盖同一个标签。<code>app:prod</code> 每次都覆盖，运行节点上拉到的到底是哪个构建很难追溯。</p><p>更稳的标签方式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>registry.example.com/ops/demo-app:1.4.2</span></span>
<span class="line"><span>registry.example.com/ops/demo-app:20260522-1530-a1b2c3d</span></span></code></pre></div><p>部署系统可以额外维护&quot;当前生产使用哪个版本&quot;的映射，但镜像标签本身要可追溯。出现故障时知道当前容器用的是哪个构建，比&quot;应该是最新版本&quot;可靠得多。</p><h2 id="常见排查" tabindex="-1">常见排查 <a class="header-anchor" href="#常见排查" aria-label="Permalink to &quot;常见排查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>检查方向</th></tr></thead><tbody><tr><td><code>docker login</code> 失败</td><td>用户名密码、机器人账号权限、证书</td></tr><tr><td><code>docker push</code> denied</td><td>项目权限、仓库是否设为只读</td></tr><tr><td>拉镜像超时</td><td>网络、DNS、代理、仓库服务状态</td></tr><tr><td>证书错误</td><td>CA 是否放到 <code>/etc/docker/certs.d/</code></td></tr><tr><td>磁盘满</td><td>Harbor data 目录、垃圾回收是否执行、旧 tag 是否清理</td></tr></tbody></table><p>排查仓库问题时先分清是客户端认证失败、TLS 失败、网络不通、还是仓库后端存储满。错误信息通常已经指向了方向，不要一上来就重启整套 Harbor。</p>`,45)])])}const g=a(n,[["render",p]]);export{c as __pageData,g as default};
